public static String encodeBase64String(byte[] binaryData) {
    if (binaryData == null) {
        return null;
    }
    // Assuming line breaks should be added for inputs larger than a certain threshold
    boolean addLineBreaks = binaryData.length > 76;
    return StringUtils.newStringUtf8(encodeBase64(binaryData, addLineBreaks));
}
